import { resolve } from 'node:path'

import { findProjectForPath, loadConfig, type ProjectEntry } from '../heartbeat/config.js'
import {
  disableManagedCaddy,
  enableManagedCaddy,
  isCaddyInstalled,
  loadManagedCaddyStatus,
  managedCaddyStartCommand,
} from '../caddy/manager.js'

export async function cmdCaddyEnable(options: { root: string }): Promise<number> {
  const project = resolveProject(options.root)
  if (project === null) {
    process.stderr.write(
      'Project not found in ~/.memorytree/config.toml. Run `memorytree daemon quick-start --root .` first.\n',
    )
    return 1
  }

  if (!isCaddyInstalled()) {
    process.stderr.write('Caddy is not installed or not available on PATH. Install Caddy first.\n')
    return 1
  }

  try {
    const result = enableManagedCaddy(project)
    process.stdout.write(`Caddy enabled for project: ${project.name}\n`)
    process.stdout.write(`Port: ${String(project.report_port)}\n`)
    process.stdout.write(`Exposure: ${project.report_exposure}\n`)
    process.stdout.write(`Report directory: ${result.reportDir}\n`)
    process.stdout.write(`Main config: ${result.mainConfigPath}\n`)
    process.stdout.write(`Project fragment: ${result.fragmentPath}\n`)
    for (const url of result.localUrls) {
      process.stdout.write(`Local URL: ${url}\n`)
    }
    for (const url of result.lanUrls) {
      process.stdout.write(`LAN URL: ${url}\n`)
    }
    return 0
  } catch (error: unknown) {
    process.stderr.write(`${formatError(error)}\n`)
    return 1
  }
}

export async function cmdCaddyDisable(options: { root: string }): Promise<number> {
  const project = resolveProject(options.root)
  if (project === null) {
    process.stderr.write(
      'Project not found in ~/.memorytree/config.toml. Run `memorytree daemon quick-start --root .` first.\n',
    )
    return 1
  }

  if (!isCaddyInstalled()) {
    process.stderr.write('Caddy is not installed or not available on PATH. Install Caddy first.\n')
    return 1
  }

  try {
    const result = disableManagedCaddy(project)
    process.stdout.write(`Caddy disabled for project: ${project.name}\n`)
    process.stdout.write(`Main config: ${result.mainConfigPath}\n`)
    process.stdout.write(`Project fragment removed: ${result.fragmentPath}\n`)
    return 0
  } catch (error: unknown) {
    process.stderr.write(`${formatError(error)}\n`)
    return 1
  }
}

export async function cmdCaddyStatus(options: { root: string }): Promise<number> {
  const project = resolveProject(options.root)
  if (project === null) {
    process.stderr.write(
      'Project not found in ~/.memorytree/config.toml. Run `memorytree daemon quick-start --root .` first.\n',
    )
    return 1
  }

  const status = await loadManagedCaddyStatus(project)
  process.stdout.write(`Caddy installed: ${yesNo(status.installed)}\n`)
  process.stdout.write(`Caddy running: ${yesNo(status.running)}\n`)
  process.stdout.write(`Using MemoryTree Caddyfile: ${yesNoOrUnknown(status.usingManagedConfig)}\n`)
  process.stdout.write(`Project registered: ${yesNo(status.fragmentExists)}\n`)
  process.stdout.write(`Port: ${String(status.port)}\n`)
  process.stdout.write(`Exposure: ${status.exposure}\n`)
  process.stdout.write(`Report directory: ${status.reportDir}\n`)
  process.stdout.write(`Main config: ${status.mainConfigPath}\n`)
  process.stdout.write(`Project fragment: ${status.fragmentPath}\n`)
  for (const url of status.localUrls) {
    process.stdout.write(`Local URL: ${url}\n`)
  }
  for (const url of status.lanUrls) {
    process.stdout.write(`LAN URL: ${url}\n`)
  }
  if (!status.installed || !status.running || status.usingManagedConfig !== true) {
    process.stdout.write(`Managed start command: ${managedCaddyStartCommand()}\n`)
  }
  return 0
}

function resolveProject(root: string): ProjectEntry | null {
  const config = loadConfig()
  return findProjectForPath(config, resolve(root))
}

function yesNo(value: boolean): string {
  return value ? 'yes' : 'no'
}

function yesNoOrUnknown(value: boolean | null): string {
  if (value === null) return 'unknown'
  return yesNo(value)
}

function formatError(error: unknown): string {
  if (error instanceof Error && error.message) {
    return error.message
  }
  return String(error)
}

import { beforeEach, afterEach, describe, expect, it, vi } from 'vitest'
import { mkdtempSync, mkdirSync, rmSync, writeFileSync } from 'node:fs'
import { join, resolve } from 'node:path'
import { tmpdir } from 'node:os'

let tmpHome: string

vi.mock('node:os', async () => {
  const actual = await vi.importActual<typeof import('node:os')>('node:os')
  return {
    ...actual,
    homedir: () => tmpHome,
  }
})

import {
  findManagedPortConflict,
  managedCaddyPaths,
  managedCaddyStartCommand,
  renderManagedMainCaddyfile,
  renderManagedProjectFragment,
} from '../../src/caddy/manager.js'
import { toPosixPath } from '../../src/utils/path.js'

beforeEach(() => {
  tmpHome = mkdtempSync(join(tmpdir(), 'memorytree-caddy-test-'))
})

afterEach(() => {
  rmSync(tmpHome, { recursive: true, force: true })
})

describe('managedCaddyPaths', () => {
  it('stores the managed config tree under ~/.memorytree/caddy', () => {
    const paths = managedCaddyPaths('demo-project')

    expect(paths.rootDir).toContain('.memorytree')
    expect(paths.mainConfigPath).toContain('.memorytree')
    expect(paths.fragmentPath).toContain(join('.memorytree', 'caddy', 'sites'))
    expect(paths.fragmentPath).toMatch(/demo-project\.caddy$/)
  })
})

describe('renderManagedMainCaddyfile', () => {
  it('imports project site fragments through a MemoryTree-owned main Caddyfile', () => {
    const text = renderManagedMainCaddyfile()

    expect(text).toContain('auto_https off')
    expect(text).toContain('import sites/*.caddy')
  })
})

describe('renderManagedProjectFragment', () => {
  it('renders a local-only site block with loopback bind', () => {
    const reportDir = resolve('Memory', '07_reports')
    const text = renderManagedProjectFragment({
      id: 'demo-project',
      name: 'Demo Project',
      report_port: 10010,
      report_exposure: 'local',
    }, reportDir)

    expect(text).toContain('# project_id: demo-project')
    expect(text).toContain('# report_port: 10010')
    expect(text).toContain('# report_exposure: local')
    expect(text).toContain('http://127.0.0.1:10010, http://localhost:10010')
    expect(text).toContain('bind 127.0.0.1 [::1]')
    expect(text).toContain(`root * "${toPosixPath(reportDir)}"`)
    expect(text).toContain('file_server')
  })

  it('renders a lan-visible site block without loopback bind restriction', () => {
    const text = renderManagedProjectFragment({
      id: 'demo-project',
      name: 'Demo Project',
      report_port: 12000,
      report_exposure: 'lan',
    }, '/workspace/demo/Memory/07_reports')

    expect(text).toContain('http://:12000')
    expect(text).not.toContain('bind 127.0.0.1')
  })
})

describe('findManagedPortConflict', () => {
  it('detects when another managed fragment already owns the same port', () => {
    const paths = managedCaddyPaths('demo-project')
    mkdirSync(paths.sitesDir, { recursive: true })
    writeFileSync(join(paths.sitesDir, 'other-project.caddy'), [
      '# project_id: other-project',
      '# report_port: 10010',
      '',
    ].join('\n'), 'utf-8')

    expect(findManagedPortConflict('demo-project', 10010)).toBe('other-project')
  })

  it('ignores the current project fragment when the port matches itself', () => {
    const paths = managedCaddyPaths('demo-project')
    mkdirSync(paths.sitesDir, { recursive: true })
    writeFileSync(paths.fragmentPath, [
      '# project_id: demo-project',
      '# report_port: 10010',
      '',
    ].join('\n'), 'utf-8')

    expect(findManagedPortConflict('demo-project', 10010)).toBeNull()
  })
})

describe('managedCaddyStartCommand', () => {
  it('points Caddy at the MemoryTree-owned main config', () => {
    expect(managedCaddyStartCommand()).toContain('caddy run --config')
    expect(managedCaddyStartCommand()).toContain('.memorytree')
    expect(managedCaddyStartCommand()).toContain('Caddyfile')
  })
})

