          typeof (parsed as Record<string, unknown>)['client'] === 'string'
        ) {
          out.push(parsed as ManifestEntry)
        }
      } catch {
        // Skip malformed manifests
      }
    } else {
      // Recurse into subdirectories
      loadManifestsRecursive(fullPath, out)
    }
  }
}

